<script>
// 确保marked库加载完成后再执行渲染
let markedLoadAttempts = 0;
function waitForMarked(callback) {
    if (typeof marked !== 'undefined') {
        console.log('marked.js loaded successfully');
        callback();
    } else if (markedLoadAttempts < 50) { // 5秒超时
        markedLoadAttempts++;
        setTimeout(() => waitForMarked(callback), 100);
    } else {
        console.error('Failed to load marked.js library, using fallback rendering');
        // 后备渲染方法：简单的换行处理
        const folderDescription = document.getElementById('folderDescriptionDisplay');
        if (folderDescription) {
            const encodedMarkdown = folderDescription.getAttribute('data-markdown');
            const tempElement = document.createElement('textarea');
            tempElement.innerHTML = encodedMarkdown;
            const markdownText = tempElement.value;
            folderDescription.innerHTML = markdownText.replace(/\n/g, '<br>');
        }
    }
}
</script>
<script>
// Markdown 渲染和编辑功能
document.addEventListener('DOMContentLoaded', function() {
    // 初始化WebSocket连接，用于接收实时更新
    const socket = io();
    const currentFolderName = '{{ folder_name }}';

    // 监听文件夹描述更新
    socket.on('folder_description_updated', function(data) {
        // 只处理当前文件夹的更新
        if (data.folder_name === currentFolderName) {
            updateFolderDescriptionDisplay(data.description);
        }
    });

    // Markdown 渲染功能
    function renderMarkdown() {
        console.log('renderMarkdown called');
        const folderDescription = document.getElementById('folderDescriptionDisplay');
        console.log('folderDescription element:', folderDescription);

        if (folderDescription) {
            const encodedMarkdown = folderDescription.getAttribute('data-markdown');
            // 解码HTML实体
            const tempElement = document.createElement('textarea');
            tempElement.innerHTML = encodedMarkdown;
            const markdownText = tempElement.value;
            console.log('Original markdown text:', markdownText);
            console.log('Encoded markdown text:', encodedMarkdown);

            if (markdownText && markdownText.trim()) {
                // 等待marked库加载
                waitForMarked(() => {
                    try {
                        console.log('marked library loaded, rendering...');

                        // 配置 marked 选项
                        const markedOptions = {
                            breaks: true,
                            gfm: true,
                            sanitize: false
                        };

                        // 检查marked版本，新版本使用不同的配置方式
                        if (marked.setOptions) {
                            marked.setOptions(markedOptions);
                        }

                        // 创建自定义渲染器
                        let renderer;
                        try {
                            renderer = new marked.Renderer();

                            // 自定义代码块渲染
                            renderer.code = function(code, lang) {
                                // 处理新版本 marked.js 的 API 变化，code 可能是对象
                                let codeText = code;
                                if (typeof code === 'object' && code.text) {
                                    codeText = code.text;
                                }

                                // 处理语言参数
                                let language = lang;
                                if (typeof lang === 'object' && lang.lang) {
                                    language = lang.lang;
                                }

                                const className = language ? `language-${language}` : '';
                                return `<pre class="code-block"><code class="${className}">${codeText}</code></pre>`;
                            };

                            // 自定义图片渲染
                            renderer.image = function(href, title, text) {
                                console.log('Processing image:', href, 'in folder:', '{{ folder_name }}');

                                // 处理新版本 marked.js 的 API 变化，href 可能是对象
                                let imageUrl = href;
                                if (typeof href === 'object' && href.href) {
                                    imageUrl = href.href;
                                }

                                // 如果是相对路径，转换为绝对路径
                                if (imageUrl && typeof imageUrl === 'string' && !imageUrl.startsWith('http') && !imageUrl.startsWith('/')) {
                                    // 获取当前文件夹路径，图片文件应该和folder_info.md在同一目录
                                    const currentFolder = '{{ folder_name }}';
                                    // 构建完整的文件路径：folder_name/image.png
                                    // 分别编码文件夹名和文件名，保留中间的斜杠
                                    const encodedFolder = encodeURIComponent(currentFolder);
                                    const encodedFileName = encodeURIComponent(imageUrl);
                                    imageUrl = `/gallery/serve/${encodedFolder}/${encodedFileName}`;
                                    console.log('Converted to:', imageUrl);
                                }

                                const titleAttr = title ? ` title="${title}"` : '';
                                return `<img src="${imageUrl}" alt="${text}"${titleAttr} style="max-width: min(600px, 100%); height: auto; border-radius: 4px; margin: 10px 0; box-shadow: 0 2px 8px rgba(255, 182, 193, 0.3);" onerror="console.error('Failed to load image:', this.src)">`;
                            };
                        } catch (e) {
                            console.warn('Failed to create custom renderer, using default:', e);
                            renderer = undefined;
                        }

                        // 渲染 markdown 并替换内容
                        let renderedHTML;
                        try {
                            // 提取 LaTeX 公式为占位符，防止 marked 破坏公式结构
                            const mathPlaceholders = [];
                            const saveMath = (match) => {
                                mathPlaceholders.push(match);
                                return `%%MATH_PH_${mathPlaceholders.length - 1}%%`;
                            };
                            let processedText = markdownText;
                            // 先提取 display math ($$...$$)，支持多行
                            processedText = processedText.replace(/\$\$([\s\S]*?)\$\$/g, (m) => saveMath(m));
                            // 再提取 inline math ($...$)，排除 $$ 的情况
                            processedText = processedText.replace(/(?<!\$)\$(?!\$)([^\$\n]+?)\$(?!\$)/g, (m) => saveMath(m));

                            const renderOptions = renderer ? { renderer: renderer } : {};
                            if (marked.parse) {
                                renderedHTML = marked.parse(processedText, renderOptions);
                            } else if (typeof marked === 'function') {
                                renderedHTML = marked(processedText, renderOptions);
                            } else {
                                throw new Error('marked function not available');
                            }
                            // 恢复 LaTeX 公式（marked 可能将占位符包裹在 <p> 标签中）
                            mathPlaceholders.forEach((math, i) => {
                                renderedHTML = renderedHTML.replace(`<p>%%MATH_PH_${i}%%</p>`, math);
                                renderedHTML = renderedHTML.replace(`%%MATH_PH_${i}%%`, math);
                            });
                        } catch (parseError) {
                            console.error('Markdown parsing failed:', parseError);
                            // 简单后备方案
                            renderedHTML = markdownText
                                .replace(/^# (.*$)/gim, '<h1>$1</h1>')
                                .replace(/^## (.*$)/gim, '<h2>$1</h2>')
                                .replace(/^### (.*$)/gim, '<h3>$1</h3>')
                                .replace(/\*\*(.*)\*\*/gim, '<strong>$1</strong>')
                                .replace(/\*(.*)\*/gim, '<em>$1</em>')
                                .replace(/```(\w+)?\n([\s\S]*?)```/gim, '<pre class="code-block"><code>$2</code></pre>')
                                .replace(/`([^`]+)`/gim, '<code>$1</code>')
                                .replace(/\n/g, '<br>');
                        }

                        console.log('Rendered HTML:', renderedHTML);
                        folderDescription.innerHTML = renderedHTML;

                        // 应用语法高亮
                        if (typeof Prism !== 'undefined') {
                            setTimeout(() => {
                                Prism.highlightAllUnder(folderDescription);
                                console.log('Syntax highlighting applied');
                            }, 100);
                        }

                        // 渲染 LaTeX 公式
                        if (typeof renderMathInElement !== 'undefined') {
                            setTimeout(() => {
                                try {
                                    renderMathInElement(folderDescription, {
                                        delimiters: [
                                            {left: '$$', right: '$$', display: true},
                                            {left: '$', right: '$', display: false},
                                            {left: '\\[', right: '\\]', display: true},
                                            {left: '\\(', right: '\\)', display: false}
                                        ],
                                        throwOnError: false,
                                        errorColor: '#cc0000'
                                    });
                                    console.log('LaTeX formulas rendered successfully');
                                } catch (error) {
                                    console.error('KaTeX rendering error:', error);
                                }
                            }, 150);
                        }

                        console.log('Markdown rendered successfully');
                    } catch (error) {
                        console.error('Markdown rendering error:', error);
                        // 如果markdown渲染失败，至少显示原始内容并换行
                        folderDescription.innerHTML = markdownText.replace(/\n/g, '<br>');
                    }
                });
            }
        }
    }

    // 文件夹编辑功能
    const folderModal = document.getElementById('folderModal');
    const folderNameInput = document.getElementById('folderName');
    const folderDescriptionTextarea = document.getElementById('folderDescription');
    const saveFolderBtn = document.getElementById('saveFolder');
    const cancelFolderBtn = document.getElementById('cancelFolder');
    const folderCloseBtn = folderModal.querySelector('.modal-close');

    let currentFolder = '';

    // 打开文件夹编辑模态框
    document.addEventListener('click', function(e) {
        if (e.target.closest('.btn-edit-folder')) {
            const btn = e.target.closest('.btn-edit-folder');
            currentFolder = btn.dataset.folder;
            const currentDescription = btn.dataset.description;

            folderNameInput.value = currentFolder;
            // 解码HTML编码的字符
            const textarea = document.createElement('textarea');
            textarea.innerHTML = currentDescription;
            folderDescriptionTextarea.value = textarea.value;
            folderModal.style.display = 'flex';
        }
    });

    // 关闭模态框
    function closeFolderModal() {
        folderModal.style.display = 'none';
        currentFolder = '';
    }

    folderCloseBtn.addEventListener('click', closeFolderModal);
    cancelFolderBtn.addEventListener('click', closeFolderModal);

    // 点击模态框外部关闭
    folderModal.addEventListener('click', function(e) {
        if (e.target === folderModal) {
            closeFolderModal();
        }
