    // 处理粘贴事件
    folderDescriptionTextarea.addEventListener('paste', function(e) {
        const clipboardData = e.clipboardData || window.clipboardData;
        if (!clipboardData) return;

        // 检查是否有图片文件
        const items = clipboardData.items;
        let hasImage = false;

        for (let i = 0; i < items.length; i++) {
            const item = items[i];

            // 处理图片粘贴
            if (item.type.indexOf('image') !== -1) {
                hasImage = true;
                e.preventDefault();

                const blob = item.getAsFile();
                if (blob) {
                    handlePastedImage(blob);
                }
                break;
            }
        }
    });

    // 处理粘贴的图片文件
    function handlePastedImage(file) {
        if (!currentFolder || isUploadingImage) return;

        isUploadingImage = true;
        showPasteOverlay('正在上传图片...');

        const formData = new FormData();
        formData.append('image', file, file.name || 'pasted_image.png');

        fetch(`/gallery/api/upload-pasted-image/${encodeURIComponent(currentFolder)}`, {
            method: 'POST',
            body: formData
        })
        .then(response => response.json())
        .then(data => {
            if (data.success) {
                // 在光标位置插入Markdown图片语法
                const textarea = folderDescriptionTextarea;
                const start = textarea.selectionStart;
                const end = textarea.selectionEnd;
                const text = textarea.value;
                const imageMarkdown = data.markdown + '\n';

                textarea.value = text.substring(0, start) + imageMarkdown + text.substring(end);

                // 更新光标位置
                textarea.selectionStart = textarea.selectionEnd = start + imageMarkdown.length;
                textarea.focus();

                // 触发保存
                updateSaveStatus('未保存');
                autoSaveFolderDescription();

                showUploadSuccess(`图片已保存: ${data.filename}`);
            } else {
                showUploadError(data.message || '上传失败');
            }
        })
        .catch(error => {
            console.error('上传图片失败:', error);
            showUploadError('网络错误，请重试');
        })
        .finally(() => {
            isUploadingImage = false;
            hidePasteOverlay();
        });
    }

