    function generateSubfolderCheckboxes() {
        subfolderCheckboxes.innerHTML = '';

        if (!availableSubfolders || availableSubfolders.length === 0) {
            subfolderCheckboxes.innerHTML = '<p style="text-align: center; color: #666; padding: 20px;">没有可选择的子文件夹</p>';
            return;
        }

        // 如果没有选中任何子文件夹，默认全选
        if (selectedSubfolders.length === 0) {
            selectedSubfolders = availableSubfolders.map(f => f.name);
        }

        availableSubfolders.forEach(subfolder => {
            const checkboxDiv = document.createElement('div');
            checkboxDiv.className = 'subfolder-checkbox';
            if (selectedSubfolders.includes(subfolder.name)) {
                checkboxDiv.classList.add('checked');
            }

            const checkbox = document.createElement('input');
            checkbox.type = 'checkbox';
            checkbox.id = `subfolder_${subfolder.name}`;
            checkbox.value = subfolder.name;
            checkbox.checked = selectedSubfolders.includes(subfolder.name);

            const label = document.createElement('label');
            label.htmlFor = checkbox.id;
            label.textContent = `${subfolder.name} (${subfolder.image_count || 0}张)`;

            checkboxDiv.appendChild(checkbox);
            checkboxDiv.appendChild(label);

            // 点击事件
            checkbox.addEventListener('change', function() {
                if (this.checked) {
                    if (!selectedSubfolders.includes(this.value)) {
                        selectedSubfolders.push(this.value);
                    }
                    checkboxDiv.classList.add('checked');
                } else {
                    selectedSubfolders = selectedSubfolders.filter(name => name !== this.value);
                    checkboxDiv.classList.remove('checked');
                }
                updateSearchIfNeeded();
            });

            // 整个区域点击切换
            checkboxDiv.addEventListener('click', function(e) {
                if (e.target !== checkbox) {
                    checkbox.click();
                }
            });

            subfolderCheckboxes.appendChild(checkboxDiv);
        });
    }

