    // 搜索子文件夹中的图片（支持懒加载）
    function searchImagesInSubfolders(query, page = 1) {
        if (!query) return;

        // 如果是新搜索，重置状态
        if (page === 1) {
            isSearchMode = true;
            currentSearchQuery = query;
            searchCurrentPage = 1;
            searchHasMore = true;
            searchTotalResults = 0;

            imageSearchLoading.style.display = 'block';
            imageSearchResultsSection.style.display = 'block';
            imageSearchResultsGrid.innerHTML = '';
            // 视图切换控件已移除

            // 显示搜索触发器
            const searchTrigger = document.getElementById('searchLoadMoreTrigger');
            if (searchTrigger) {
                searchTrigger.style.display = 'block';
            }
        } else {
            // 加载更多搜索结果
            imageSearchLoading.style.display = 'block';
        }

        const currentFolder = '{{ folder_name }}';

        // 判断是否有子文件夹，如果有则搜索子文件夹，否则搜索当前文件夹
        const hasSubfolders = {{ 'true' if subfolders and subfolders|length > 0 else 'false' }};

        let searchUrl;
        if (hasSubfolders && selectedSubfolders.length > 0) {
            // 构建选中子文件夹的搜索URL
            const selectedFoldersParam = selectedSubfolders.map(name => encodeURIComponent(name)).join(',');
            searchUrl = `/gallery/api/search-in-selected-subfolders/${currentFolder}?q=${encodeURIComponent(query)}&subfolders=${selectedFoldersParam}&page=${page}&per_page=20`;
        } else if (hasSubfolders) {
            // 有子文件夹，搜索所有子文件夹
            searchUrl = `/gallery/api/search-in-subfolders/${currentFolder}?q=${encodeURIComponent(query)}&page=${page}&per_page=20`;
        } else {
            // 没有子文件夹，搜索当前文件夹内的文件
            searchUrl = `/gallery/api/search?q=${encodeURIComponent(query)}&folder=${encodeURIComponent(currentFolder)}&type=image`;
        }

        fetch(searchUrl)
            .then(response => response.json())
            .then(data => {
                imageSearchLoading.style.display = 'none';
                searchIsLoading = false;

                if (data.success) {
                    if (hasSubfolders) {
                        // 新的分页API响应格式，data.data包含images数组和分页信息
                        let newImages = [];
                        if (data.data && data.data.images) {
                            newImages = data.data.images;
                            searchCurrentPage = data.data.page;
                            searchHasMore = data.data.has_next;
                            searchTotalResults = data.data.total;
                        } else {
                            newImages = data.data || [];
                            searchHasMore = false;
                        }

                        if (page === 1) {
                            imageSearchResults = newImages;
                            displayImageSearchResults(imageSearchResults, query);
                        } else {
                            imageSearchResults = imageSearchResults.concat(newImages);
                            appendImageSearchResults(newImages);
                        }
                    } else {
                        imageSearchResults = data.data;
                        displayCurrentFolderSearchResults(imageSearchResults, query);
                        searchHasMore = false;
                    }
                } else {
                    imageSearchResultsGrid.innerHTML = `<div style="text-align: center; padding: 40px; color: #666;">
                        <i class="fas fa-exclamation-triangle" style="font-size: 3rem; margin-bottom: 15px; color: #ffc107;"></i>
                        <h3>搜索失败</h3>
                        <p>${data.message}</p>
                    </div>`;
