    // 调整图片容器高度以匹配图片实际高度
    function adjustImageThumbnailHeight(card) {
        // 支持两种不同的样式结构
        const thumbnail = card.querySelector('.image-thumbnail') || card.querySelector('.described-image-preview');
        const img = card.querySelector('.image-thumbnail img, .image-thumbnail object') || 
                   card.querySelector('.described-image-preview img, .described-image-preview object');

        if (!thumbnail || !img) return;

        function updateHeight() {
            try {
                // 重置高度让图片自然显示
                if (thumbnail) {
                    thumbnail.style.height = 'auto';
                }

                // 稍后获取图片的实际渲染高度
                setTimeout(() => {
                    if (!img || !thumbnail) return;

                    const actualHeight = img.offsetHeight || img.getBoundingClientRect().height;

                    if (actualHeight > 0) {
                        thumbnail.style.height = actualHeight + 'px';
                    } else {
                        // 如果获取不到高度，尝试其他方法
                        if (img.tagName === 'OBJECT') {
                            try {
                                const svgDoc = img.contentDocument;
                                if (svgDoc) {
                                    const svg = svgDoc.documentElement;
                                    if (svg) {
                                        const rect = svg.getBoundingClientRect();
                                        if (rect.height > 0) {
                                            thumbnail.style.height = rect.height + 'px';
                                            return;
                                        }
                                    }
                                }
                            } catch (e) {
                                // 跨域问题或其他错误，忽略
                                console.warn('SVG content access failed:', e);
                            }
                        } else if (img.tagName === 'IMG' && img.complete && img.naturalHeight > 0) {
                            // 根据容器宽度和图片原始比例计算高度
                            const containerWidth = thumbnail.offsetWidth;
                            if (containerWidth > 0 && img.naturalWidth > 0) {
                                const aspectRatio = img.naturalHeight / img.naturalWidth;
                                const calculatedHeight = containerWidth * aspectRatio;
                                thumbnail.style.height = calculatedHeight + 'px';
                            }
                        }
                    }
                }, 50);
            } catch (error) {
                console.warn('Error in updateHeight:', error);
            }
        }

        // 立即尝试更新高度
        updateHeight();

        // 为图片加载事件添加监听器
        try {
            if (img && img.tagName === 'IMG') {
                img.addEventListener('load', updateHeight);
                img.addEventListener('error', function() {
                    // 如果图片加载失败，设置合理的高度
                    if (thumbnail) {
                        thumbnail.style.height = '200px';
                    }
                });
            } else if (img && img.tagName === 'OBJECT') {
                img.addEventListener('load', updateHeight);
                // 延迟检查，给object内容时间加载
                setTimeout(updateHeight, 100);
                setTimeout(updateHeight, 500);
                setTimeout(updateHeight, 1000);
            }

            // 窗口大小改变时重新调整
            if (thumbnail && 'ResizeObserver' in window) {
                const resizeObserver = new ResizeObserver(() => {
                    updateHeight();
                });
                resizeObserver.observe(thumbnail);
            }
        } catch (error) {
            console.warn('Error setting up image height adjustment:', error);
        }
    }

