    // ========== Markdown 图片灯箱功能 ==========
    function initMarkdownLightbox() {
        const lightbox = document.getElementById('markdownLightbox');
        const lightboxImg = document.getElementById('markdownLightboxImg');
        const lightboxClose = document.getElementById('markdownLightboxClose');
        const lightboxCaption = document.getElementById('markdownLightboxCaption');
        const lightboxContent = document.getElementById('markdownLightboxContent');
        const zoomInBtn = document.getElementById('lightboxZoomIn');
        const zoomOutBtn = document.getElementById('lightboxZoomOut');
        const zoomLevel = document.getElementById('lightboxZoomLevel');
        const resetBtn = document.getElementById('lightboxReset');
        const folderDescription = document.getElementById('folderDescriptionDisplay');

        if (!lightbox || !lightboxImg || !folderDescription) return;

        // 缩放状态
        let currentZoom = 1;
        let isDragging = false;
        let startX, startY, translateX = 0, translateY = 0;
        const MIN_ZOOM = 0.5;
        const MAX_ZOOM = 5;
        const ZOOM_STEP = 0.25;

        // 更新缩放显示
        function updateZoom() {
            lightboxImg.style.transform = `translate(${translateX}px, ${translateY}px) scale(${currentZoom})`;
            zoomLevel.textContent = Math.round(currentZoom * 100) + '%';

            // 根据缩放级别启用/禁用按钮
            zoomOutBtn.disabled = currentZoom <= MIN_ZOOM;
            zoomInBtn.disabled = currentZoom >= MAX_ZOOM;

            // 添加/移除 zoomed 类用于光标样式
            if (currentZoom > 1) {
                lightboxImg.classList.add('zoomed');
            } else {
                lightboxImg.classList.remove('zoomed');
                // 重置位置当缩放回1时
                if (currentZoom === 1) {
                    translateX = 0;
                    translateY = 0;
                    lightboxImg.style.transform = `scale(1)`;
                }
            }
        }

        // 放大
        zoomInBtn.addEventListener('click', function() {
            if (currentZoom < MAX_ZOOM) {
                currentZoom = Math.min(currentZoom + ZOOM_STEP, MAX_ZOOM);
                updateZoom();
            }
        });

        // 缩小
        zoomOutBtn.addEventListener('click', function() {
            if (currentZoom > MIN_ZOOM) {
                currentZoom = Math.max(currentZoom - ZOOM_STEP, MIN_ZOOM);
                if (currentZoom === 1) {
                    translateX = 0;
                    translateY = 0;
                }
                updateZoom();
            }
        });

        // 重置
        resetBtn.addEventListener('click', function() {
            currentZoom = 1;
            translateX = 0;
            translateY = 0;
            updateZoom();
        });

        // 鼠标滚轮缩放
        lightboxContent.addEventListener('wheel', function(e) {
            e.preventDefault();
            const delta = e.deltaY > 0 ? -ZOOM_STEP : ZOOM_STEP;
            const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, currentZoom + delta));
            if (newZoom !== currentZoom) {
                currentZoom = newZoom;
                if (currentZoom === 1) {
                    translateX = 0;
                    translateY = 0;
                }
                updateZoom();
            }
        });

        // 拖拽功能
        lightboxImg.addEventListener('mousedown', function(e) {
            if (currentZoom > 1) {
                isDragging = true;
                startX = e.clientX - translateX;
                startY = e.clientY - translateY;
                lightboxImg.style.cursor = 'grabbing';
            }
        });

        document.addEventListener('mousemove', function(e) {
            if (isDragging) {
                e.preventDefault();
                translateX = e.clientX - startX;
                translateY = e.clientY - startY;
                updateZoom();
            }
        });

        document.addEventListener('mouseup', function() {
            if (isDragging) {
                isDragging = false;
                lightboxImg.style.cursor = currentZoom > 1 ? 'grab' : 'zoom-out';
            }
        });

        // 为 markdown 区域的图片添加点击事件
        folderDescription.addEventListener('click', function(e) {
            if (e.target.tagName === 'IMG') {
                e.preventDefault();
                e.stopPropagation();

                const img = e.target;
                lightboxImg.src = img.src;

                // 修复：获取 alt 文本，如果没有则使用空字符串
                const altText = img.getAttribute('alt');
                lightboxCaption.textContent = (altText && altText !== 'undefined') ? altText : '';
                lightboxCaption.style.display = (altText && altText !== 'undefined') ? 'block' : 'none';

                // 重置缩放状态
                currentZoom = 1;
                translateX = 0;
                translateY = 0;
                updateZoom();

                lightbox.classList.add('active');
                document.body.style.overflow = 'hidden';
            }
        });

        // 关闭灯箱
        function closeLightbox() {
            lightbox.classList.remove('active');
            document.body.style.overflow = '';
            setTimeout(() => {
                lightboxImg.src = '';
                lightboxCaption.textContent = '';
                // 重置缩放
                currentZoom = 1;
                translateX = 0;
                translateY = 0;
                updateZoom();
            }, 300);
        }

        // 点击关闭按钮
        lightboxClose.addEventListener('click', closeLightbox);

        // 点击图片不关闭，让使用者可以点击拖拽
        lightboxImg.addEventListener('click', function(e) {
            if (!isDragging && currentZoom === 1) {
                // 只有在未拖拽且未缩放时才关闭
                closeLightbox();
            }
        });

        // 点击背景关闭
        lightbox.addEventListener('click', function(e) {
            if (e.target === lightbox || e.target === lightboxContent) {
                closeLightbox();
            }
        });

        // ESC 键关闭
        document.addEventListener('keydown', function(e) {
            if (e.key === 'Escape' && lightbox.classList.contains('active')) {
                closeLightbox();
            }
        });
    }

    // 初始化灯箱
    initMarkdownLightbox();

    // ========== 因子相关性分析功能 ==========
    const floatingCorrelationBtn = document.getElementById('floatingCorrelationBtn');
    const floatingCorrelationWindow = document.getElementById('floatingCorrelationWindow');
    const floatingCorrelationClose = document.getElementById('floatingCorrelationClose');
    const correlationFactorsList = document.getElementById('correlationFactorsList');
    const correlationFactorVersion = document.getElementById('correlationFactorVersion');
    const correlationFactorCount = document.getElementById('correlationFactorCount');
    const calculateCorrelationBtn = document.getElementById('calculateCorrelationBtn');
    const clearCorrelationBtn = document.getElementById('clearCorrelationBtn');
    const correlationHistoryList = document.getElementById('correlationHistoryList');
    const correlationResultModal = document.getElementById('correlationResultModal');

    // 从folder_name解析因子版本
    const folderPath = '{{ folder_name }}';
    const pathParts = folderPath.split('/');
    const factorVersion = pathParts.length >= 2 ? pathParts[1] : pathParts[0];

    // localStorage key
    const STORAGE_KEY = 'correlation_selected_factors';

    // 已选因子列表
    let selectedFactors = [];
    let currentCorrelationResult = null;

    // 从localStorage加载选中因子
    function loadSelectedFactors() {
        try {
            const saved = localStorage.getItem(STORAGE_KEY);
            if (saved) {
                selectedFactors = JSON.parse(saved);
            }
        } catch (e) {
            selectedFactors = [];
        }
        updateFactorsList();
        updateCorrelationBtnBadge();
    }

    // 保存选中因子到localStorage
    function saveSelectedFactors() {
        try {
            localStorage.setItem(STORAGE_KEY, JSON.stringify(selectedFactors));
        } catch (e) {
            console.error('保存失败:', e);
        }
    }

    // 页面加载时恢复选中状态
    loadSelectedFactors();

    // 打开相关性分析悬浮窗
    if (floatingCorrelationBtn && floatingCorrelationWindow) {
        floatingCorrelationBtn.addEventListener('click', function() {
            if (floatingCorrelationWindow.classList.contains('show')) {
                floatingCorrelationWindow.classList.remove('show');
            } else {
                floatingCorrelationWindow.classList.add('show');
                correlationFactorVersion.textContent = factorVersion;
                loadCorrelationHistory();
            }
        });

        floatingCorrelationClose.addEventListener('click', function() {
            floatingCorrelationWindow.classList.remove('show');
        });

        // 点击外部关闭
        document.addEventListener('click', function(e) {
            if (floatingCorrelationWindow && floatingCorrelationWindow.classList.contains('show') && 
                !floatingCorrelationWindow.contains(e.target) && !floatingCorrelationBtn.contains(e.target)) {
                floatingCorrelationWindow.classList.remove('show');
            }
        });
    }

    // 添加因子到相关性分析
    document.addEventListener('click', function(e) {
        if (e.target.closest('.btn-add-correlation')) {
            e.stopPropagation();
            const btn = e.target.closest('.btn-add-correlation');
            const factorName = btn.dataset.factorName;

            const exists = selectedFactors.some(f => f.name === factorName && f.version === factorVersion);

            if (factorName && !exists) {
                selectedFactors.push({name: factorName, version: factorVersion});
                saveSelectedFactors();
                updateFactorsList();
                updateCorrelationBtnBadge();
            }
        }
    });

    // 更新因子列表显示
    function updateFactorsList() {
        if (selectedFactors.length === 0) {
            correlationFactorsList.innerHTML = '<p class="empty-hint">点击图片下方的"相关性"按钮添加因子</p>';
            calculateCorrelationBtn.disabled = true;
        } else {
            correlationFactorsList.innerHTML = selectedFactors.map((factor, index) => `
                <div class="correlation-factor-item">
                    <span class="factor-name" title="${factor.name} (${factor.version})">${index + 1}. ${factor.name} <small style="color:#999">[${factor.version}]</small></span>
                    <button class="remove-factor" data-index="${index}">
                        <i class="fas fa-times"></i>
                    </button>
                </div>
            `).join('');
            calculateCorrelationBtn.disabled = selectedFactors.length < 2;
        }
        correlationFactorCount.textContent = selectedFactors.length;

        correlationFactorsList.querySelectorAll('.remove-factor').forEach(btn => {
            btn.addEventListener('click', function(e) {
                e.stopPropagation();
                const index = parseInt(this.dataset.index);
                selectedFactors.splice(index, 1);
                saveSelectedFactors();
                updateFactorsList();
                updateCorrelationBtnBadge();
            });
        });
    }

    // 更新按钮徽章
    function updateCorrelationBtnBadge() {
        let badge = floatingCorrelationBtn.querySelector('.badge');
        if (selectedFactors.length > 0) {
            if (!badge) {
                badge = document.createElement('span');
                badge.className = 'badge';
                floatingCorrelationBtn.appendChild(badge);
            }
            badge.textContent = selectedFactors.length;
        } else if (badge) {
            badge.remove();
        }
    }

    // 清空因子列表
    clearCorrelationBtn.addEventListener('click', function() {
        selectedFactors = [];
        saveSelectedFactors();
        updateFactorsList();
        updateCorrelationBtnBadge();
    });

    // 计算相关性
    calculateCorrelationBtn.addEventListener('click', function() {
        if (selectedFactors.length < 2) return;

        this.disabled = true;
        this.innerHTML = '<i class="fas fa-spinner fa-spin"></i> 计算中...';

        fetch('/gallery/api/correlation/calculate', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({
                factor_list: selectedFactors
            })
        })
        .then(response => response.json())
        .then(data => {
            if (data.success) {
                currentCorrelationResult = data;
                showCorrelationResult(data);
                loadCorrelationHistory();
                floatingCorrelationWindow.classList.remove('show');
            } else {
                alert('计算失败: ' + data.message);
            }
        })
        .catch(error => {
            console.error('Error:', error);
            alert('计算时发生错误');
        })
        .finally(() => {
            this.disabled = false;
            this.innerHTML = '<i class="fas fa-calculator"></i> 计算相关性';
        });
    });

    // 显示相关性结果
    function showCorrelationResult(data) {
        const resultFactorVersion = document.getElementById('resultFactorVersion');
        const resultFactorCount = document.getElementById('resultFactorCount');
        const tableHead = document.getElementById('correlationTableHead');
        const tableBody = document.getElementById('correlationTableBody');
        const missingWarning = document.getElementById('missingFactorsWarning');
        const missingText = document.getElementById('missingFactorsText');

        resultFactorVersion.textContent = data.factor_version;
        resultFactorCount.textContent = data.factor_names.length;

        if (data.missing_factors && data.missing_factors.length > 0) {
            missingText.textContent = `以下因子未找到数据: ${data.missing_factors.join(', ')}`;
            missingWarning.style.display = 'block';
        } else {
            missingWarning.style.display = 'none';
        }

        const names = data.factor_names;
        const matrix = data.correlation_matrix;
        const n = names.length;

        let tableHeadHtml = '<tr><th></th>';
        names.forEach(name => {
            tableHeadHtml += `<th>${name}</th>`;
        });
        tableHeadHtml += '</tr>';
        tableHead.innerHTML = tableHeadHtml;

        let tableBodyHtml = '';
        for (let i = 0; i < n; i++) {
            tableBodyHtml += `<tr><th>${names[i]}</th>`;
            for (let j = 0; j < n; j++) {
                const corr = matrix[i][j];
                const absCorr = Math.abs(corr);
                const intensity = Math.floor(absCorr * 255);
                const bgColor = i === j ? '#e8f5e9' : `rgba(255, ${255 - intensity}, ${255 - intensity}, 0.3)`;
                const className = i === j ? 'diagonal' : '';
                tableBodyHtml += `<td class="${className}" style="background: ${bgColor}">${corr.toFixed(3)}</td>`;
            }
            tableBodyHtml += '</tr>';
        }
        tableBody.innerHTML = tableBodyHtml;

        correlationResultModal.style.display = 'flex';
    }

    // 关闭结果模态框
    correlationResultModal.querySelector('.modal-close').addEventListener('click', function() {
        correlationResultModal.style.display = 'none';
    });

    document.getElementById('closeResultBtn').addEventListener('click', function() {
        correlationResultModal.style.display = 'none';
    });

    correlationResultModal.addEventListener('click', function(e) {
        if (e.target === correlationResultModal) {
            correlationResultModal.style.display = 'none';
        }
    });

    document.getElementById('saveToHistoryBtn').addEventListener('click', function() {
        alert('计算时已自动保存到历史记录');
    });

    // 历史记录数据缓存
    let historyDataCache = [];

    // 加载历史记录
    function loadCorrelationHistory() {
        fetch('/gallery/api/correlation/history')
        .then(response => response.json())
        .then(data => {
            if (data.success && data.data.length > 0) {
                historyDataCache = data.data;
                const htmlParts = data.data.map(record => `
                    <div class="history-item" data-id="${record.id}">
                        <div class="history-item-info">
                            <div class="version">${record.factor_version}</div>
                            <div class="factors">${record.factor_names.length}个因子: ${record.factor_names.slice(0, 3).join(', ')}${record.factor_names.length > 3 ? '...' : ''}</div>
                            <div class="time">${new Date(record.timestamp).toLocaleString('zh-CN')}</div>
                        </div>
                        <button class="history-item-delete" data-id="${record.id}">
                            <i class="fas fa-trash"></i>
                        </button>
                    </div>
                `);
                correlationHistoryList.innerHTML = htmlParts.join('');
            } else {
                historyDataCache = [];
                correlationHistoryList.innerHTML = '<p class="empty-hint">暂无历史记录</p>';
            }
        })
        .catch(error => {
            console.error('Error loading history:', error);
            correlationHistoryList.innerHTML = '<p class="empty-hint">加载失败</p>';
        });
    }

    // 使用事件委托处理历史记录点击和删除
    correlationHistoryList.addEventListener('click', function(e) {
        e.stopPropagation();
        const deleteBtn = e.target.closest('.history-item-delete');
        if (deleteBtn) {
            e.preventDefault();
            const id = deleteBtn.dataset.id;
            if (confirm('确定删除此历史记录？')) {
                fetch(`/gallery/api/correlation/history/${id}`, {method: 'DELETE'})
                .then(response => response.json())
                .then(data => {
                    if (data.success) {
                        loadCorrelationHistory();
                    } else {
                        alert('删除失败: ' + (data.message || '未知错误'));
                    }
                })
                .catch(err => {
                    console.error('删除请求失败:', err);
                    alert('删除请求失败');
                });
            }
            return;
        }

        const historyItem = e.target.closest('.history-item');
        if (historyItem) {
            const id = historyItem.dataset.id;
            const record = historyDataCache.find(r => r.id === id);
            if (record) {
                currentCorrelationResult = record;
                showCorrelationResult(record);
                floatingCorrelationWindow.classList.remove('show');
            }
        }
    });
});
</script>

